import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";
import FilePreview from "../components/FilePreview";
import { addComplaintRequest } from "../services/api";

function AddComplaint() {
	const navigate = useNavigate();

	const [title, setTitle] = useState("");
	const [description, setDescription] = useState("");
	const [file, setFile] = useState(null);
	const [loading, setLoading] = useState(false);
	const [error, setError] = useState("");
	const [success, setSuccess] = useState("");

	const handleSubmit = async (event) => {
		event.preventDefault();
		setError("");
		setSuccess("");

		if (!title.trim() || !description.trim()) {
			setError("Title and description are required.");
			return;
		}

		const formData = new FormData();
		formData.append("title", title.trim());
		formData.append("description", description.trim());

		if (file) {
			formData.append("file", file);
		}

		try {
			setLoading(true);
			await addComplaintRequest(formData);

			setSuccess("Complaint submitted successfully.");
			setTitle("");
			setDescription("");
			setFile(null);
		} catch (err) {
			setError(err?.response?.data?.message || "Failed to submit complaint.");
		} finally {
			setLoading(false);
		}
	};

	return (
		<>
			<Navbar />

			<div className="page-wrap">
				<div className="container" style={{ maxWidth: 840 }}>
					<div className="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
						<h3 className="mb-0">Submit New Complaint</h3>
						<button className="btn btn-outline-primary" onClick={() => navigate("/complaints")}>
							View Complaints
						</button>
					</div>

					<div className="panel-card">
						{error && <div className="alert alert-danger">{error}</div>}
						{success && <div className="alert alert-success">{success}</div>}

						<form onSubmit={handleSubmit}>
							<div className="mb-3">
								<label htmlFor="title" className="form-label">
									Complaint Title
								</label>
								<input
									id="title"
									className="form-control"
									placeholder="Example: Delay in policy approval"
									value={title}
									onChange={(event) => setTitle(event.target.value)}
								/>
							</div>

							<div className="mb-3">
								<label htmlFor="description" className="form-label">
									Description
								</label>
								<textarea
									id="description"
									rows="5"
									className="form-control"
									placeholder="Describe the complaint with relevant details."
									value={description}
									onChange={(event) => setDescription(event.target.value)}
								/>
							</div>

							<div className="mb-3">
								<label htmlFor="file" className="form-label">
									Attachment (optional)
								</label>
								<input
									id="file"
									type="file"
									className="form-control"
									onChange={(event) => setFile(event.target.files?.[0] || null)}
								/>
							</div>

							<FilePreview file={file} />

							<button type="submit" className="btn btn-primary mt-3" disabled={loading}>
								{loading ? "Submitting..." : "Submit Complaint"}
							</button>
						</form>
					</div>
				</div>
			</div>
		</>
	);
}

export default AddComplaint;
